import streamlit as stimport pandas as pdimport plotly.express as pximport plotly.graph_objects as gofrom datetime import datetime# --- 1. SAYFA VE KURUMSAL AYARLAR ---st.set_page_config(page_title="Focus AI | Bostanlı Çözüm VIP", layout="wide", initial_sidebar_state="expanded")# --- 2. ÖSYM MÜFREDAT VE SON 5 YIL (2021-2025) SORU ANALİZ VERİTABANI ---MÜFREDAT_DATA = {    "TYT Matematik": {        "Problemler": 12, "Sayılar": 3, "Permütasyon-Kombinasyon": 2, "Fonksiyonlar": 1, "Üslü Sayılar": 1,         "Köklü Sayılar": 1, "Rasyonel Sayılar": 1, "Mantık": 1, "Kümeler": 1, "Polinomlar": 1, "Bölme-Bölünebilme": 1    },    "AYT Matematik": {        "Türev": 4, "İntegral": 4, "Trigonometri": 4, "Logaritma": 2, "Limit": 2, "Diziler": 1,         "Karmaşık Sayılar": 1, "İkinci Derece Denklemler": 1, "Polinomlar (AYT)": 1    },    "TYT Türkçe": {        "Paragraf": 26, "Cümlede Anlam": 3, "Sözcükte Anlam": 3, "Yazım Kuralları": 2,         "Noktalama İşaretleri": 2, "Ses Bilgisi": 1, "Dil Bilgisi": 3    },    "AYT Edebiyat": {        "Divan Edebiyatı": 5, "Cumhuriyet Dönemi": 4, "Şiir Bilgisi": 3, "Tanzimat-Servet-i Fünun": 3,        "Edebi Sanatlar": 2, "Halk Edebiyatı": 2, "İslamiyet Öncesi": 1    },    "Geometri (TYT/AYT)": {        "Çokgenler ve Dörtgenler": 2, "Çember ve Daire": 2, "Analitik Geometri": 2, "Katı Cisimler": 2, "Üçgenler": 2    },    "TYT Fen (F-K-B)": {        "Optik": 1, "Isı ve Sıcaklık": 1, "Kimya Bilimi": 1, "Atomun Yapısı": 1, "Hücre": 1, "Kalıtım": 1    },    "AYT Fen (F-K-B)": {        "Modern Fizik": 2, "Elektrik ve Manyetizma": 3, "Organik Kimya": 3, "Sıvı Çözeltiler": 1, "Sistemler (Biyoloji)": 4    }}# --- 3. MERKEZİ HAFIZA (SESSION STATE) ---# Sistem açık kaldığı sürece verileri burada tutar.for key in ['ogrenciler', 'program', 'denemeler', 'ajanda', 'video_takip']:    if key not in st.session_state:        if key == 'ogrenciler':            st.session_state[key] = pd.DataFrame(columns=["Ad Soyad", "Alan", "Veli Tel"])        elif key == 'program':            st.session_state[key] = pd.DataFrame(columns=["Öğrenci", "Ders", "Konu", "Soru Yükü", "Durum", "Kaynak"])        else:            st.session_state[key] = pd.DataFrame()# --- 4. YÖNETİM PANELİ (SIDEBAR) ---st.sidebar.title("🎯 Focus AI v4.0")st.sidebar.info("Bostanlı Çözüm VIP - Yönetim Paneli")role = st.sidebar.radio("Sistem Girişi:", ["👨‍🏫 KOÇ / ÖĞRETMEN", "🎓 ÖĞRENCİ PANELİ"])ogrenci_listesi = st.session_state.ogrenciler["Ad Soyad"].tolist() if not st.session_state.ogrenciler.empty else ["Lütfen Kayıt Yapın"]# ==========================================# 👨‍🏫 MODÜL 1: KOÇ / ÖĞRETMEN YÖNETİMİ# ==========================================if role == "👨‍🏫 KOÇ / ÖĞRETMEN":    st.title("🚀 Focus AI: Master Operasyon Merkezi")    tabs = st.tabs(["🎯 Stratejik Ödevlendirme", "📊 Gelişim & Analiz", "📅 Ajanda & Rehber", "✂️ Test & Video Gönder"])    # --- TAB 1: STRATEJİK ÖDEV ---    with tabs[0]:        st.subheader("🛠️ ÖSYM Müfredat Atama (Soru Ağırlıklı)")        with st.form("odev_ata"):            c1, c2 = st.columns(2)            o_sec = c1.selectbox("Öğrenci Seç", ogrenci_listesi)            d_sec = c2.selectbox("Ders Seç", list(MÜFREDAT_DATA.keys()))            k_sec = st.multiselect("Atanacak Konular", list(MÜFREDAT_DATA[d_sec].keys()))            kaynak = st.text_input("Kaynak (Kitap/Link)")                        if st.form_submit_button("Programa İşle"):                if o_sec != "Lütfen Kayıt Yapın":                    for kon in k_sec:                        s_yuku = MÜFREDAT_DATA[d_sec][kon]                        yeni_g = pd.DataFrame([[o_sec, d_sec, kon, s_yuku, "Bekliyor", kaynak]], columns=st.session_state.program.columns)                        st.session_state.program = pd.concat([st.session_state.program, yeni_g], ignore_index=True)                    st.success(f"{len(k_sec)} Konu Stratejik Olarak Atandı!")    # --- TAB 2: GELİŞİM & RADAR ---    with tabs[1]:        st.subheader("🕸️ Akademik Başarı Haritası")        if not st.session_state.program.empty:            # Başarı Puanı Hesaplama (Soru Yüküne Göre)            prog_df = st.session_state.program            prog_df["Basari_Puanı"] = prog_df.apply(lambda x: x["Soru Yükü"] if x["Durum"] == "Tamamlandı" else 0, axis=1)            analiz = prog_df.groupby("Öğrenci")["Basari_Puanı"].sum().reset_index()                        col_g1, col_g2 = st.columns(2)            with col_g1:                st.write("### 🏆 Focus AI Başarı Ligi")                st.dataframe(analiz.sort_values("Basari_Puanı", ascending=False), use_container_width=True)                        with col_g2:                # Radar Grafik (Örnek Görselleştirme)                fig_radar = go.Figure(data=go.Scatterpolar(r=[35, 30, 20, 25], theta=['Matematik', 'Türkçe', 'Fen', 'Sosyal'], fill='toself'))                fig_radar.update_layout(polar=dict(radialaxis=dict(visible=True, range=[0, 40])), title="Öğrenci Gelişim Radarı")                st.plotly_chart(fig_radar, use_container_width=True)    # --- TAB 3: AJANDA & REHBER ---    with tabs[2]:        st.subheader("👤 Öğrenci Kaydı ve İletişim")        with st.expander("➕ Yeni Öğrenci & Veli Tanımla"):            c_ad = st.text_input("Ad Soyad")            c_alan = st.selectbox("Alan", ["Sayısal", "EA", "Sözel", "Dil"])            c_tel = st.text_input("Veli Tel (905XXXXXXXXX)")            if st.button("Kaydı Tamamla"):                yeni_o = pd.DataFrame([[c_ad, c_alan, c_tel]], columns=st.session_state.ogrenciler.columns)                st.session_state.ogrenciler = pd.concat([st.session_state.ogrenciler, yeni_o], ignore_index=True)                st.rerun()                st.write("### 📇 Kayıtlı Rehber")        st.dataframe(st.session_state.ogrenciler, use_container_width=True)                # WhatsApp Bildirim Sistemi        if not st.session_state.ogrenciler.empty:            st.write("---")            st.subheader("📩 WhatsApp Veli Bilgilendirme")            sel_o = st.selectbox("Rapor Gönderilecek Öğrenci", ogrenci_listesi)            veli_tel = st.session_state.ogrenciler[st.session_state.ogrenciler["Ad Soyad"] == sel_o]["Veli Tel"].values[0]            msg = f"Sayın Velimiz, öğrencimiz {sel_o} bugün Focus AI sisteminde kritik TYT-AYT konularını başarıyla tamamlamıştır."            st.link_button("🟢 WhatsApp Raporunu Gönder", f"https://wa.me/{veli_tel}?text={msg.replace(' ', '%20')}")    # --- TAB 4: TEST & VİDEO GÖNDERİMİ ---    with tabs[3]:        st.subheader("✂️ Dijital İçerik ve Soru Havuzu")        st.info("PDF'den soru kırpma veya YouTube Playlist atama işlemleri buradan yapılır.")        uploaded_file = st.file_uploader("Soru Bankası PDF Yükle", type="pdf")        if uploaded_file:            st.success("PDF başarıyla yüklendi. Kırpma arayüzü aktif.")        st.button("Seçili Soruları Teste Dönüştür ve Gönder")# ==========================================# 🎓 MODÜL 2: ÖĞRENCİ PANELİ# ==========================================else:    st.title("🎓 Focus AI: Öğrenci Gelişim Portalı")    st.info(f"Hoş geldin! Bugün senin için sisteme tanımlanmış görevler aşağıdadır. Başarılar! 🚀")        # Öğrenci Görev Listesi    if not st.session_state.program.empty:        st.write("### 📅 Günlük Çalışma Programın")        for index, row in st.session_state.program.iterrows():            if row["Durum"] == "Bekliyor":                with st.container():                    col_p1, col_p2 = st.columns([5, 1])                    # Soru yükünü vurgulayarak öğrenciye ciddiyeti gösteriyoruz                    col_p1.warning(f"📌 **{row['Ders']}** | {row['Konu']} (Yıllık Ortalama: **{row['Soru Yükü']}** Soru!) - Kaynak: {row['Kaynak']}")                    if col_p2.button("Tamamladım ✅", key=index):                        st.session_state.program.at[index, "Durum"] = "Tamamlandı"                        st.rerun()    else:        st.balloons()        st.success("Harika! Şu an bekleyen bir görevin bulunmuyor. Yeni görevler için koçunla iletişime geç.")    st.write("---")    st.subheader("📺 Sana Atanan Videolar")    st.video("https://www.youtube.com/watch?v=dQw4w9WgXcQ") # Örnek Playlist/Video